// RegisterEdgeCaseServiceHandlerWithProvider registers handlers for the specified LLM provider
func RegisterEdgeCaseServiceHandlerWithProvider(s runtime.MCPServer, srv EdgeCaseServiceServer, provider runtime.LLMProvider, opts ...runtime.Option) {
	switch provider {
	case runtime.LLMProviderOpenAI:
		RegisterEdgeCaseServiceHandlerOpenAI(s, srv, opts...)
	case runtime.LLMProviderStandard:
		fallthrough
	default:
		RegisterEdgeCaseServiceHandler(s, srv, opts...)
	}
}

